
* {
  margin: 0;
  padding: 0;
}
#app {
  font-family: 'Avenir', Helvetica, Arial, sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}
#app header {

  height: 4rem;
  width: 100%;
  background-color: #eee; 
  line-height: 4rem;
  font-size: 1.2rem;
  text-align: center;
}
#app nav {
  background-color: rgba(183, 172, 172, 0.29);
  width: 14rem;
  float: left;
  height: 600px;
}
#app nav ul {
  height: 100%;
}
#app nav ul li {
  height: 2rem;
  line-height: 2rem;
  font-size: 1.1rem;
}
#app nav ul li a{
  display: inline-block;
  width: 100%;
  /*padding-left: 1rem;*/
  text-decoration: none;
}
#app nav ul li a:hover{
  background-color: #000;
  color: #fff;
}
#app .container{
  float: left;
  margin-left: 14rem;
}
#app td{
  border: 1px solid #eee;
}
#app nav ul li.active a {
  background-color: #000;
  color: #fff;
}
.color-y {
  color: red;
}



